      && verifier.VerifyString(tablePos, 4 /*REQUEST_ID*/, true)
      && verifier.VerifyString(tablePos, 6 /*MODULE_ID*/, true)
      && verifier.VerifyString(tablePos, 8 /*MODULE_VERSION*/, false)
      && verifier.VerifyString(tablePos, 10 /*CONTENT_KEY_ID*/, false)
      && verifier.VerifyString(tablePos, 12 /*RECIPIENT_KEY_ID*/, false)
      && verifier.VerifyField(tablePos, 14 /*ALGORITHM*/, 1 /*licensingWrappedKeyAlgorithm*/, 1, false)
      && verifier.VerifyVectorOfData(tablePos, 16 /*REQUESTER_EPHEMERAL_PUBKEY*/, 1 /*byte*/, false)
      && verifier.VerifyVectorOfData(tablePos, 18 /*PROVIDER_EPHEMERAL_PUBKEY*/, 1 /*byte*/, false)
      && verifier.VerifyVectorOfData(tablePos, 20 /*HKDF_SALT*/, 1 /*byte*/, false)
      && verifier.VerifyVectorOfData(tablePos, 22 /*IV*/, 1 /*byte*/, false)
      && verifier.VerifyVectorOfData(tablePos, 24 /*CIPHERTEXT*/, 1 /*byte*/, false)
      && verifier.VerifyVectorOfData(tablePos, 26 /*TAG*/, 1 /*byte*/, false)
      && verifier.VerifyField(tablePos, 28 /*EXPIRES_AT*/, 8 /*ulong*/, 8, false)
      && verifier.VerifyTableEnd(tablePos);
  }
}
